{
var bgInput = inputs.Length > 0 ? inputs[0] : null;
var health = GetFloat(parameters, "health", 0.7f);
var width = GetFloat(parameters, "width", 0.8f);
var height = GetFloat(parameters, "height", 0.1f);
var colorMode = GetChoice(parameters, "colorMode", "health");
var customColor = GetColor(parameters, "customColor", Color.FromRgb(60, 200, 80));
var borderColor = GetColor(parameters, "borderColor", Color.FromRgb(180, 160, 140));
var bgColor = GetColor(parameters, "bgColor", Color.FromRgb(60, 50, 45));
var offsetX = GetFloat(parameters, "offsetX", 0f);
var offsetY = GetFloat(parameters, "offsetY", 0f);
var showBorder = GetBool(parameters, "showBorder", true);

var tileSize = context.TileSize;
var buffer = bgInput != null ? bgInput.Clone() : new PixelBuffer(tileSize, tileSize);

// Pick fill color based on mode and health level
var (fillR, fillG, fillB) = colorMode switch
{
    "mana" => (0.3f, 0.4f, 1f),
    "stamina" => (1f, 0.8f, 0.2f),
    "custom" => (customColor.R / 255f, customColor.G / 255f, customColor.B / 255f),
    _ => health switch
    {
        <= 0.25f => (1f, 0.2f, 0.2f),      // Red when low
        <= 0.5f => (1f, 0.6f, 0.2f),        // Orange when mid
        _ => (0.3f, 0.8f, 0.25f)             // Green when healthy
    }
};

var bR = borderColor.R / 255f; var bG = borderColor.G / 255f; var bB = borderColor.B / 255f;
var bgR = bgColor.R / 255f; var bgG = bgColor.G / 255f; var bgB = bgColor.B / 255f;

var halfSize = tileSize * 0.5f;
var barWidth = tileSize * width;
var barHeight = tileSize * height;
var barLeft = halfSize - barWidth * 0.5f + offsetX * tileSize;
var barTop = halfSize - barHeight * 0.5f + offsetY * tileSize;
var borderPx = showBorder ? Math.Max(1f, barHeight * 0.1f) : 0f;

buffer.ParallelForEachPixel((x, y) =>
{
    // Check if pixel is in bar area
    if (x < barLeft || x > barLeft + barWidth || y < barTop || y > barTop + barHeight)
        return;

    // Border
    if (showBorder)
    {
        var dx = MathF.Min(x - barLeft, barLeft + barWidth - x);
        var dy = MathF.Min(y - barTop, barTop + barHeight - y);
        if (dx < borderPx || dy < borderPx)
        {
            // Border highlight on top/left, shadow on bottom/right
            var isTopLeft = (x - barLeft < borderPx && y - barTop < borderPx) ||
                            x - barLeft < borderPx || y - barTop < borderPx;
            var hl = isTopLeft ? 0.3f : -0.2f;
            buffer.SetPixel(x, y,
                Math.Clamp(bR + hl, 0f, 1f),
                Math.Clamp(bG + hl, 0f, 1f),
                Math.Clamp(bB + hl, 0f, 1f), 1f);
            return;
        }
    }

    var innerLeft = barLeft + borderPx;
    var innerWidth = barWidth - borderPx * 2;
    var fillEdge = innerLeft + innerWidth * health;

    if (x < fillEdge)
    {
        // Fill area with subtle gradient
        var relX = (x - innerLeft) / innerWidth;
        var gradient = 0.9f + (1f - relX) * 0.1f;

        // Subtle inner highlight at top
        var innerTop = barTop + borderPx;
        var innerHeight = barHeight - borderPx * 2;
        var topHL = Math.Clamp(1f - (y - innerTop) / (innerHeight * 0.5f), 0f, 1f) * 0.15f;

        buffer.SetPixel(x, y,
            Math.Clamp(fillR * gradient + topHL, 0f, 1f),
            Math.Clamp(fillG * gradient + topHL, 0f, 1f),
            Math.Clamp(fillB * gradient + topHL, 0f, 1f), 1f);
    }
    else
    {
        // Background (empty) area with slight darkening
        var darken = 0.7f;
        buffer.SetPixel(x, y,
            bgR * darken, bgG * darken, bgB * darken, 1f);
    }
});

return buffer;
}
